import React, { useState, useEffect } from 'react'
import { supabase } from './lib/supabaseClient'
import { Login } from './components/auth/Login'
import { Register } from './components/auth/Register'

function App() {
  const [user, setUser] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const path = window.location.pathname

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null)
      setLoading(false)
    })
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null)
    })
    return () => subscription.unsubscribe()
  }, [])

  if (loading) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#0a0a0a', color:'#FFD700', fontSize:'20px' }}>
      Loading...
    </div>
  )

  if (path === '/register') return <Register />
  if (!user) return <Login />

  return (
    <div style={{ minHeight:'100vh', background:'#0a0a0a', color:'white', padding:'40px' }}>
      <div style={{ maxWidth:'600px', margin:'0 auto' }}>
        <h1 style={{ color:'#FFD700' }}>Welcome, {user.user_metadata?.full_name || user.email}! 👋</h1>
        <p style={{ color:'#888' }}>You are logged in! Supabase is working!</p>
        <button
          onClick={async () => { await supabase.auth.signOut(); window.location.reload() }}
          style={{ marginTop:'20px', padding:'10px 24px', background:'#c8a200', border:'none', borderRadius:'8px', color:'#0a0a0a', fontWeight:'bold', cursor:'pointer', fontSize:'16px' }}>
          Logout
        </button>
      </div>
    </div>
  )
}

export default App
